import { Toaster } from "@/components/ui/toaster"
import { QueryClientProvider } from '@tanstack/react-query'
import { queryClientInstance } from '@/lib/query-client'
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom';
import PageNotFound from './lib/PageNotFound';
import { AuthProvider, useAuth } from '@/lib/AuthContext';
import UserNotRegisteredError from '@/components/UserNotRegisteredError';
import Layout from './components/Layout';
import PublicLayout from './components/PublicLayout';
import Dashboard from './pages/Dashboard';
import Orders from './pages/Orders';
import OrderDetail from './pages/OrderDetail';
import SmartBoxes from './pages/SmartBoxes';
import Alerts from './pages/Alerts';
import System from './pages/System';
import Home from './pages/Home';
import Features from './pages/Features';
import Demo from './pages/Demo';
import Contact from './pages/Contact';

const AuthenticatedApp = () => {
  const { isLoadingAuth, isLoadingPublicSettings, authError, navigateToLogin } = useAuth();

  if (isLoadingPublicSettings || isLoadingAuth) {
    return (
      <div className="fixed inset-0 flex items-center justify-center bg-background">
        <div className="w-8 h-8 border-4 border-primary/20 border-t-primary rounded-full animate-spin"></div>
      </div>
    );
  }

  if (authError) {
    if (authError.type === 'user_not_registered') {
      return <UserNotRegisteredError />;
    } else if (authError.type === 'auth_required') {
      navigateToLogin();
      return null;
    }
  }

  return (
    <Routes>
      <Route element={<PublicLayout />}>
        <Route path="/home" element={<Home />} />
        <Route path="/features" element={<Features />} />
        <Route path="/demo" element={<Demo />} />
        <Route path="/contact" element={<Contact />} />
      </Route>
      <Route element={<Layout />}>
        <Route path="/" element={<Dashboard />} />
        <Route path="/orders" element={<Orders />} />
        <Route path="/orders/:orderId" element={<OrderDetail />} />
        <Route path="/smartboxes" element={<SmartBoxes />} />
        <Route path="/alerts" element={<Alerts />} />
        <Route path="/system" element={<System />} />
      </Route>
      <Route path="*" element={<PageNotFound />} />
    </Routes>
  );
};

function App() {
  return (
    <AuthProvider>
      <QueryClientProvider client={queryClientInstance}>
        <Router>
          <AuthenticatedApp />
        </Router>
        <Toaster />
      </QueryClientProvider>
    </AuthProvider>
  )
}

export default App

import { Outlet, Link, useLocation } from 'react-router-dom';
import { useState } from 'react';
import {
  LayoutDashboard, Package, Box, Bell, Activity,
  ChevronLeft, ChevronRight, Wifi, WifiOff, Menu, X
} from 'lucide-react';
import { cn } from '@/lib/utils';

const navItems = [
  { path: '/', label: 'Dashboard', icon: LayoutDashboard },
  { path: '/orders', label: '─É╞ín h├áng', icon: Package },
  { path: '/smartboxes', label: 'SmartBox', icon: Box },
  { path: '/alerts', label: 'Cß║únh b├ío', icon: Bell },
  { path: '/system', label: 'Hß╗ç thß╗æng', icon: Activity },
];

export default function Layout() {
  const [collapsed, setCollapsed] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);
  const location = useLocation();

  return (
    <div className="flex h-screen bg-background overflow-hidden">
      {/* Mobile overlay */}
      {mobileOpen && (
        <div className="fixed inset-0 bg-black/60 z-40 md:hidden" onClick={() => setMobileOpen(false)} />
      )}

      {/* Sidebar */}
      <aside className={cn(
        "fixed md:relative z-50 h-full flex flex-col bg-sidebar border-r border-border transition-all duration-300",
        collapsed ? "w-16" : "w-60",
        mobileOpen ? "translate-x-0" : "-translate-x-full md:translate-x-0"
      )}>
        {/* Logo */}
        <div className={cn("flex items-center gap-3 px-4 py-5 border-b border-border", collapsed && "justify-center px-0")}>
          <div className="w-8 h-8 rounded-lg bg-primary flex items-center justify-center flex-shrink-0">
            <Box className="w-4 h-4 text-primary-foreground" />
          </div>
          {!collapsed && (
            <div>
              <div className="text-sm font-semibold text-foreground">SmartBox</div>
              <div className="text-xs text-muted-foreground">E-Logistics</div>
            </div>
          )}
        </div>

        {/* Nav */}
        <nav className="flex-1 px-2 py-4 space-y-1 overflow-y-auto">
          {navItems.map(({ path, label, icon: Icon }) => (
            <Link
              key={path}
              to={path}
              onClick={() => setMobileOpen(false)}
              className={cn(
                "flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-all duration-150",
                location.pathname === path
                  ? "bg-primary/15 text-primary border border-primary/20"
                  : "text-muted-foreground hover:text-foreground hover:bg-secondary",
                collapsed && "justify-center px-0"
              )}
            >
              <Icon className="w-4 h-4 flex-shrink-0" />
              {!collapsed && <span>{label}</span>}
            </Link>
          ))}
        </nav>

        {/* Status */}
        {!collapsed && (
          <div className="px-4 py-3 border-t border-border">
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-primary animate-pulse" />
              <span className="text-xs text-muted-foreground">MQTT Connected</span>
            </div>
          </div>
        )}

        {/* Collapse btn */}
        <button
          onClick={() => setCollapsed(!collapsed)}
          className="hidden md:flex items-center justify-center py-3 border-t border-border text-muted-foreground hover:text-foreground transition-colors"
        >
          {collapsed ? <ChevronRight className="w-4 h-4" /> : <ChevronLeft className="w-4 h-4" />}
        </button>
      </aside>

      {/* Main */}
      <div className="flex-1 flex flex-col overflow-hidden">
        {/* Top bar */}
        <header className="h-14 border-b border-border flex items-center justify-between px-4 md:px-6 bg-card/50 backdrop-blur-sm flex-shrink-0">
          <button className="md:hidden text-muted-foreground" onClick={() => setMobileOpen(true)}>
            <Menu className="w-5 h-5" />
          </button>
          <div className="flex items-center gap-2">
            <span className="text-xs font-mono text-muted-foreground hidden sm:block">SmartBox E-Logistics v1.0</span>
          </div>
          <div className="flex items-center gap-3">
            <div className="flex items-center gap-1.5 text-xs text-primary">
              <Wifi className="w-3.5 h-3.5" />
              <span className="hidden sm:block">Live</span>
            </div>
            <div className="w-px h-4 bg-border" />
            <div className="text-xs text-muted-foreground font-mono">
              {new Date().toLocaleTimeString('vi-VN')}
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 md:p-6">
          <Outlet />
        </main>
      </div>
    </div>
  );
}

import { cn } from '@/lib/utils';
import { Thermometer, Droplets, Zap, Battery, MapPin } from 'lucide-react';

function GaugeBar({ value, min, max, warningMin, warningMax, color }) {
  const pct = Math.min(100, Math.max(0, ((value - min) / (max - min)) * 100));
  const isWarning = value < warningMin || value > warningMax;
  return (
    <div className="w-full h-1.5 bg-secondary rounded-full overflow-hidden">
      <div
        className={cn("h-full rounded-full transition-all duration-500", isWarning ? "bg-red-400" : color)}
        style={{ width: `${pct}%` }}
      />
    </div>
  );
}

export default function SensorGauge({ data }) {
  const sensors = [
    {
      label: 'Nhiß╗çt ─æß╗Ö', value: data?.temperature, unit: '┬░C',
      icon: Thermometer, min: -20, max: 60, warningMin: -5, warningMax: 35, color: 'bg-primary',
    },
    {
      label: '─Éß╗Ö ß║⌐m', value: data?.humidity, unit: '%',
      icon: Droplets, min: 0, max: 100, warningMin: 20, warningMax: 80, color: 'bg-blue-400',
    },
    {
      label: 'Va chß║ím', value: data?.shock_g, unit: 'G',
      icon: Zap, min: 0, max: 10, warningMin: 0, warningMax: 3, color: 'bg-amber-400',
    },
    {
      label: 'Pin', value: data?.battery, unit: '%',
      icon: Battery, min: 0, max: 100, warningMin: 20, warningMax: 100, color: 'bg-green-400',
    },
  ];

  return (
    <div className="grid grid-cols-2 gap-3">
      {sensors.map(({ label, value, unit, icon: Icon, min, max, warningMin, warningMax, color }) => {
        const val = value ?? '--';
        const isWarning = typeof value === 'number' && (value < warningMin || value > warningMax);
        return (
          <div key={label} className={cn(
            "bg-secondary/50 rounded-xl p-3 border",
            isWarning ? "border-red-400/40" : "border-border"
          )}>
            <div className="flex items-center gap-2 mb-2">
              <Icon className={cn("w-3.5 h-3.5", isWarning ? "text-red-400" : "text-muted-foreground")} />
              <span className="text-xs text-muted-foreground">{label}</span>
            </div>
            <div className={cn("text-xl font-semibold font-mono mb-2", isWarning ? "text-red-400" : "text-foreground")}>
              {typeof val === 'number' ? val.toFixed(1) : val}<span className="text-xs text-muted-foreground ml-1">{unit}</span>
            </div>
            {typeof value === 'number' && (
              <GaugeBar value={value} min={min} max={max} warningMin={warningMin} warningMax={warningMax} color={color} />
            )}
          </div>
        );
      })}
    </div>
  );
}

