import { useState, useEffect } from 'react';
import { base44 } from '@/api/base44Client';
import AlertBadge from '../components/AlertBadge';
import { Bell, CheckCircle, Filter } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';
import { format } from 'date-fns';

export default function Alerts() {
  const [alerts, setAlerts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('unresolved');

  useEffect(() => {
    base44.entities.Alert.list('-created_date', 100).then(data => {
      setAlerts(data);
      setLoading(false);
    });
    const unsub = base44.entities.Alert.subscribe((event) => {
      if (event.type === 'create') setAlerts(prev => [event.data, ...prev]);
      if (event.type === 'update') setAlerts(prev => prev.map(a => a.id === event.id ? event.data : a));
    });
    return () => unsub();
  }, []);

  const filtered = alerts.filter(a => {
    if (filter === 'unresolved') return !a.is_resolved;
    if (filter === 'critical') return !a.is_resolved && (a.severity === 'Cao' || a.severity === 'Khß║⌐n cß║Ñp');
    return true;
  });

  const resolve = async (id) => {
    await base44.entities.Alert.update(id, { is_resolved: true, resolved_at: new Date().toISOString() });
    setAlerts(prev => prev.map(a => a.id === id ? { ...a, is_resolved: true } : a));
  };

  if (loading) return (
    <div className="flex items-center justify-center h-64">
      <div className="w-8 h-8 border-4 border-primary/20 border-t-primary rounded-full animate-spin" />
    </div>
  );

